(function(){ if(window.__dzFxInit) return; window.__dzFxInit=true; const revealObs=new IntersectionObserver(function(entries){ entries.forEach(function(e){ if(e.isIntersecting){ e.target.classList.add('visible'); revealObs.unobserve(e.target); } }); },{threshold:0.12, rootMargin:'0px 0px -40px 0px'}); document.querySelectorAll('.dz-reveal').forEach(function(el,i){ el.style.transitionDelay=(i)*0.07+'s'; revealObs.observe(el); }); document.querySelectorAll('.dz-3d-card,.svc-card,.review-card').forEach(function(card){ card.addEventListener('mousemove',function(ev){ const r=card.getBoundingClientRect(); const x=(ev.clientX-r.left)/r.width-.5; const y=(ev.clientY-r.top)/r.height-.5; card.style.transform='perspective(1000px) rotateX('+(-y*10)+'deg) rotateY('+(x*7)+'deg) translateY(-6px)'; }); card.addEventListener('mouseleave',function(){ card.style.transform=''; }); }); document.querySelectorAll('.btn-primary,.btn-wa-lg,.btn-nav-cta').forEach(function(btn){ btn.addEventListener('mousemove',function(ev){ const r=btn.getBoundingClientRect(); const dx=(ev.clientX-(r.left+r.width/2))*.18; const dy=(ev.clientY-(r.top+r.height/2))*.18; btn.style.transform='translate('+dx+'px,'+dy+'px)'; }); btn.addEventListener('mouseleave',function(){ btn.style.transform=''; }); }); const hero=document.querySelector('.hero-photo'); if(hero){ window.addEventListener('scroll',function(){ const y=Math.min(window.scrollY*.16,72); hero.style.transform='translateY('+y+'px) scale(1.03)'; },{passive:true}); } })();